  1→import React, {useMemo, useState} from 'react';
  2→import {
  3→  FlatList,
  4→  Pressable,
  5→  ScrollView,
  6→  StyleSheet,
  7→  Text,
  8→  View,
  9→} from 'react-native';
 10→import {useInfiniteQuery, useMutation} from '@tanstack/react-query';
 11→import {BottomTabScreenProps} from '@react-navigation/bottom-tabs';
 12→import {CompositeScreenProps} from '@react-navigation/native';
 13→import {NativeStackScreenProps} from '@react-navigation/native-stack';
 14→import {SafeAreaView} from 'react-native-safe-area-context';
 15→import {PostCard} from '../../components/PostCard/PostCard';
 16→import {PostCardSkeleton} from '../../components/SkeletonLoader';
 17→import {CommentModal} from '../../components/Comments';
 18→import {RepostModal} from '../../components/RepostModal';
 19→import {Chip} from '../../components/Chip';
 20→import {EmptyState} from '../../components/EmptyState';
 21→import {PenIcon} from '../../components/icons';
 22→import {useAuth} from '../../features/auth/AuthProvider';
 23→import {useTheme} from '../../theme/ThemeProvider';
 24→import {fonts, typeScale} from '../../theme/typography';
 25→import {spacing, radii, shadows} from '../../theme/spacing';
 26→import {
 27→  mobileApi,
 28→  type CursorPage,
 29→  type JournalItem,
 30→} from '../../lib/api/mobileApi';
 31→import {socialApi} from '../../lib/api/socialApi';
 32→import {queryClient} from '../../lib/queryClient';
 33→import {useBookmarkMutation} from '../../hooks/useSocialMutations';
 34→import {
 35→  extractPlainText,
 36→  extractBannerImage,
 37→  resolveCount,
 38→  getNextCursor,
 39→} from '../../lib/utils/journalHelpers';
 40→import type {MainTabParamList, RootStackParamList} from '../../navigation/types';
 41→
 42→type Props = CompositeScreenProps<
 43→  BottomTabScreenProps<MainTabParamList, 'Home'>,
 44→  NativeStackScreenProps<RootStackParamList>
 45→>;
 46→
 47→const PAGE_SIZE = 10;
 48→
 49→const QUICK_ACTIONS = [
 50→  {key: 'all', label: 'All'},
 51→  {key: 'journal', label: 'Journals'},
 52→] as const;
 53→
 54→export function HomeFeedScreen({navigation}: Props) {
 55→  const {user, session} = useAuth();
 56→  const {colors} = useTheme();
 57→  const token = session?.access_token ?? '';
 58→  const [refreshing, setRefreshing] = useState(false);
 59→  const [activeFilter, setActiveFilter] = useState('all');
 60→  const [commentModal, setCommentModal] = useState<{postId: string; receiverId?: string; commentCount: number} | null>(null);
 61→  const [repostModal, setRepostModal] = useState<{journalId: string; title?: string; authorName?: string; authorAvatar?: string} | null>(null);
 62→
 63→  const feedQuery = useInfiniteQuery({
 64→    queryKey: ['feed', user?.id],
 65→    queryFn: ({pageParam}) =>
 66→      mobileApi.getJournals(pageParam ?? null, PAGE_SIZE, user?.id),
 67→    initialPageParam: null as string | null,
 68→    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
 69→  });
 70→
 71→  const reactionMutation = useMutation({
 72→    mutationFn: async ({
 73→      journalId,
 74→      receiverId,
 75→      reactionType,
 76→    }: {
 77→      journalId: string;
 78→      receiverId: string;
 79→      reactionType: string;
 80→    }) => {
 81→      if (!token) throw new Error('Please log in to react.');
 82→      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
 83→    },
 84→    onMutate: async ({journalId, reactionType}) => {
 85→      await queryClient.cancelQueries({queryKey: ['feed']});
 86→      const prev = queryClient.getQueryData<{pages: CursorPage<JournalItem>[]}>(
 87→        ['feed', user?.id],
 88→      );
 89→      if (prev) {
 90→        queryClient.setQueryData<{pages: CursorPage<JournalItem>[]}>(
 91→          ['feed', user?.id],
 92→          old => {
 93→            if (!old) return old;
 94→            return {
 95→              ...old,
 96→              pages: old.pages.map(page => ({
 97→                ...page,
 98→                data: page.data.map(item => {
 99→                  if (item.id !== journalId) return item;
100→                  const removing = item.user_reaction === reactionType;
101→                  const currentCount =
102→                    (item.reaction_count?.[0]?.count ??
103→                      item.like_count?.[0]?.count ??
104→                      item.likes_count ??
105→                      0) as number;
106→                  const delta = removing ? -1 : item.user_reaction ? 0 : 1;
107→                  return {
108→                    ...item,
109→                    user_reaction: removing ? null : reactionType,
110→                    has_liked: removing ? false : true,
111→                    like_count: [{count: Math.max(0, currentCount + delta)}],
112→                  };
113→                }),
114→              })),
115→            };
116→          },
117→        );
118→      }
119→      return {prev};
120→    },
121→    onError: (_err, _vars, context) => {
122→      if (context?.prev) {
123→        queryClient.setQueryData(['feed', user?.id], context.prev);
124→      }
125→    },
126→    onSettled: () => {
127→      queryClient.invalidateQueries({queryKey: ['feed']});
128→    },
129→  });
130→
131→  const bookmarkMutation = useBookmarkMutation(token, ['feed', user?.id]);
132→
133→  const handleReact = (journalId: string, receiverId: string, reactionType: string) => {
134→    if (!token) return;
135→    reactionMutation.mutate({journalId, receiverId, reactionType});
136→  };
137→
138→  const handleComment = (journalId: string, receiverId?: string, commentCount?: number) => {
139→    setCommentModal({postId: journalId, receiverId, commentCount: commentCount ?? 0});
140→  };
141→
142→  const handleBookmark = (journalId: string) => {
143→    bookmarkMutation.mutate(journalId);
144→  };
145→
146→  const handleRepost = (journalId: string, title?: string, authorName?: string, authorAvatar?: string) => {
147→    setRepostModal({journalId, title, authorName, authorAvatar});
148→  };
149→
150→  const posts = useMemo(
151→    () => feedQuery.data?.pages.flatMap(page => page.data ?? []) ?? [],
152→    [feedQuery.data?.pages],
153→  );
154→
155→  const onRefresh = async () => {
156→    setRefreshing(true);
157→    try {
158→      await feedQuery.refetch();
159→    } finally {
160→      setRefreshing(false);
161→    }
162→  };
163→
164→  const handleQuickAction = (key: string) => {
165→    setActiveFilter(key);
166→  };
167→
168→  return (
169→    <SafeAreaView
170→      style={[styles.safe, {backgroundColor: colors.bgPrimary}]}
171→      edges={['top']}>
172→      {/* Branded header */}
173→      <View
174→        style={[
175→          styles.header,
176→          {borderBottomColor: colors.borderCard},
177→        ]}>
178→        <Text style={[styles.brandText, {color: colors.textHeading}]}>
179→          iskrib
180→        </Text>
181→      </View>
182→
183→      {/* Filter chips */}
184→      <View style={styles.chipRow}>
185→        <ScrollView
186→          horizontal
187→          showsHorizontalScrollIndicator={false}
188→          contentContainerStyle={styles.chipScroll}>
189→          {QUICK_ACTIONS.map(action => (
190→            <Chip
191→              key={action.key}
192→              label={action.label}
193→              active={activeFilter === action.key}
194→              onPress={() => handleQuickAction(action.key)}
195→            />
196→          ))}
197→        </ScrollView>
198→      </View>
199→
200→      {/* Feed */}
201→      <FlatList
202→        data={posts}
203→        onRefresh={onRefresh}
204→        refreshing={refreshing}
205→        onEndReachedThreshold={0.25}
206→        onEndReached={() => {
207→          if (feedQuery.hasNextPage && !feedQuery.isFetchingNextPage) {
208→            feedQuery.fetchNextPage();
209→          }
210→        }}
211→        contentContainerStyle={styles.listContent}
212→        showsVerticalScrollIndicator={false}
213→        ListEmptyComponent={
214→          feedQuery.isLoading ? (
215→            <View style={styles.skeletonList}>
216→              <PostCardSkeleton />
217→              <PostCardSkeleton />
218→              <PostCardSkeleton />
219→            </View>
220→          ) : (
221→            <EmptyState
222→              title="No posts yet"
223→              subtitle="Pull to refresh or create your first journal post."
224→            />
225→          )
226→        }
227→        ListFooterComponent={
228→          feedQuery.isFetchingNextPage ? (
229→            <View style={styles.loadingMore}>
230→              <PostCardSkeleton />
231→            </View>
232→          ) : null
233→        }
234→        keyExtractor={item => item.id}
235→        renderItem={({item}) => {
236→          const preview = extractPlainText(item.content).slice(0, 180);
237→          const likeCount = resolveCount(
238→            item.like_count,
239→            item.likes_count,
240→          );
241→          const commentCount = resolveCount(
242→            item.comment_count,
243→            item.comments_count,
244→          );
245→          const bookmarkCount = resolveCount(item.bookmark_count);
246→          const bannerImage = extractBannerImage(
247→            item.content,
248→            (item as any).images,
249→          );
250→
251→          const receiverId = item.user_id ?? item.users?.id ?? '';
252→
253→          const handleAuthorPress = () => {
254→            const authorId = item.users?.id ?? item.user_id;
255→            if (!authorId) return;
256→            if (authorId === user?.id) {
257→              navigation.navigate('Main' as any, {screen: 'Profile'});
258→            } else {
259→              navigation.navigate('VisitProfile', {
260→                userId: authorId,
261→                username: item.users?.username ?? undefined,
262→              });
263→            }
264→          };
265→
266→          const isRepost = !!item.is_repost;
267→          const repostSource = isRepost ? item.repost_source : null;
268→          const repostSourcePreview = repostSource?.content
269→            ? extractPlainText(repostSource.content).slice(0, 180)
270→            : '';
271→
272→          return (
273→            <PostCard
274→              title={item.title || 'Untitled Post'}
275→              bodyPreview={preview || 'No preview text available.'}
276→              authorName={item.users?.name || 'Unknown author'}
277→              authorAvatar={item.users?.image_url}
278→              authorBadge={item.users?.badge as 'legend' | 'og' | undefined}
279→              bannerImage={bannerImage}
280→              postType={item.post_type}
281→              likeCount={likeCount}
282→              commentCount={commentCount}
283→              bookmarkCount={bookmarkCount}
284→              userReaction={item.user_reaction}
285→              isBookmarked={!!item.has_bookmarked}
286→              onReact={type => handleReact(item.id, receiverId, type)}
