import {useMemo, useState} from 'react';
import {useQuery} from '@tanstack/react-query';
import {mobileApi, type JournalItem, type UserPreview} from '../lib/api/mobileApi';

export type SearchTab = 'all' | 'users' | 'posts';

export function useSearch() {
  const [query, setQuery] = useState('');
  const [activeTab, setActiveTab] = useState<SearchTab>('all');

  const normalizedQuery = useMemo(() => query.trim(), [query]);
  const isSearching = normalizedQuery.length >= 2;

  const usersQuery = useQuery({
    queryKey: ['search-users', normalizedQuery],
    enabled: isSearching && activeTab !== 'posts',
    queryFn: () => mobileApi.searchUsers(normalizedQuery, 10),
  });

  const journalsQuery = useQuery({
    queryKey: ['search-journals', normalizedQuery],
    enabled: isSearching && activeTab !== 'users',
    queryFn: () => mobileApi.searchJournals(normalizedQuery, 10),
  });

  const users: UserPreview[] = usersQuery.data?.data ?? [];
  const journals: JournalItem[] = journalsQuery.data?.data ?? [];

  return {
    query,
    setQuery,
    activeTab,
    setActiveTab,
    isSearching,
    normalizedQuery,
    users,
    journals,
  };
}

